SELECT * FROM web_sales, item, date_dim, web_returns, catalog_sales, catalog_returns, store_sales, store_returns WHERE i_item_sk = ws_item_sk AND d_date_sk = ws_sold_date_sk AND (ws_order_number = wr_order_number AND ws_item_sk = wr_item_sk) AND i_item_sk = cs_item_sk AND d_date_sk = cs_sold_date_sk AND (cs_order_number = cr_order_number AND cs_item_sk = cr_item_sk) AND i_item_sk = ss_item_sk AND d_date_sk = ss_sold_date_sk AND (ss_ticket_number = sr_ticket_number AND ss_item_sk = sr_item_sk);
